import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getFeatured, getCategories } from '../services/api';
import ProductCard from '../components/ProductCard';

const Home = () => {
  const [featured, setFeatured] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [f, c] = await Promise.all([getFeatured(), getCategories()]);
        setFeatured(f.data);
        setCategories(c.data);
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
    };
    load();
  }, []);

  return (
    <div className="home">
      {/* Hero */}
      <section className="hero">
        <div className="hero-content">
          <p className="hero-sub">New Collection 2026</p>
          <h1>Elevate Your Style with <span>SAS Collection</span></h1>
          <p className="hero-desc">Discover premium fashion for every occasion. Quality fabrics, timeless designs.</p>
          <div className="hero-btns">
            <Link to="/products" className="btn-primary btn-lg">Shop Now</Link>
            <Link to="/products?isFeatured=true" className="btn-ghost btn-lg">View Collection</Link>
          </div>
        </div>
        <div className="hero-image">
          <div className="hero-badge">New Arrivals</div>
        </div>
      </section>


const categoryImages = {{
  Men: 'https://unsplash.com',
  Women: 'https://www.galaxybags.com.pk/cdn/shop/files/1688_image_share_cb6ed136df85b3a1b774953f4756b47c_1920x.jpg?v=1715265763',
  Kids: 'https://unsplash.com',
  Accessories: 'https://unsplash.com',
  Footwear: 'https://unsplash.com',
  Sale: 'https://unsplash.com'
}};

{/* 2. Update the JSX */}
<section className="section">
  <div className="section-header">
    <h2>Shop by Category</h2>
    <Link to="/products">View All →</Link>
  </div>
  <div className="category-grid">
    {Object.keys(categoryImages).map(cat => (
      <Link to={`/products?category=${cat}`} key={cat} className="category-card">
        <div className="category-image-container">
          <img 
            src={categoryImages[cat]} 
            alt={cat} 
            className="category-img" 
          />
        </div>
        <span>{cat}</span>
      </Link>
    ))}
  </div>
</section>


      {/* Featured */}
      <section className="section">
        <div className="section-header">
          <h2>Featured Products</h2>
          <Link to="/products">See All →</Link>
        </div>
        {loading ? <div className="loader">Loading...</div> : (
          <div className="products-grid">
            {featured.map(p => <ProductCard key={p._id} product={p} />)}
          </div>
        )}
      </section>

      {/* Promo Banner */}
      <section className="promo-banner">
        <div className="promo-content">
          <h2>Get 20% Off Your First Order</h2>
          <p>Use code <strong>WELCOME20</strong> at checkout</p>
          <Link to="/register" className="btn-primary">Sign Up & Save</Link>
        </div>
      </section>
    </div>
  );
};

export default Home;
